import{_ as e,c as a,a2 as d,o as r}from"./chunks/framework.CehHI-68.js";const g=JSON.parse('{"title":"AI 功能","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai.md","filePath":"zh/guide/ai.md","lastUpdated":1775790217000}'),i={name:"guide/ai.md"};function l(o,t,s,n,c,p){return r(),a("div",null,t[0]||(t[0]=[d('<h1 id="ai" tabindex="-1">AI 功能 <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI 功能 {#ai}&quot;">​</a></h1><p>兰空图床集成了 AI 能力，支持对图片进行智能润色、自动打标签、自动生成描述。系统支持多个 AI 供应商，管理员可以在后台创建和管理 AI 驱动，并通过角色组控制用户的 AI 使用权限和配额。</p><h2 id="supported-providers" tabindex="-1">支持的供应商 <a class="header-anchor" href="#supported-providers" aria-label="Permalink to &quot;支持的供应商 {#supported-providers}&quot;">​</a></h2><table tabindex="0"><thead><tr><th>供应商</th><th style="text-align:center;">图片润色</th><th style="text-align:center;">打标签</th><th style="text-align:center;">生成描述</th></tr></thead><tbody><tr><td>OpenAI</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Google Gemini</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>火山引擎（豆包）</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>智谱 AI（GLM）</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>阿里百炼（通义千问）</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>月之暗面（Kimi）</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">关于图片润色</p><p>图片润色需要供应商支持图片生成能力，阿里百炼和月之暗面目前仅支持文本能力，因此不支持图片润色功能。</p></div><h2 id="capabilities" tabindex="-1">AI 能力说明 <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;AI 能力说明 {#capabilities}&quot;">​</a></h2><h3 id="image-enhance" tabindex="-1">图片润色 <a class="header-anchor" href="#image-enhance" aria-label="Permalink to &quot;图片润色 {#image-enhance}&quot;">​</a></h3><p>通过自然语言描述，让 AI 对图片进行编辑和增强处理。例如：「将背景替换为蓝天白云」、「提高图片亮度和对比度」、「将图片转为水彩画风格」等。</p><p>用户提交润色任务时可以选择是否替换原图，如果不替换，系统会生成一张新图片。</p><h3 id="tagging" tabindex="-1">自动打标签 <a class="header-anchor" href="#tagging" aria-label="Permalink to &quot;自动打标签 {#tagging}&quot;">​</a></h3><p>AI 会自动分析图片内容，生成准确的描述性标签。系统支持自动识别中英文，并根据图片内容返回合适语言的标签。</p><h3 id="description" tabindex="-1">自动生成描述 <a class="header-anchor" href="#description" aria-label="Permalink to &quot;自动生成描述 {#description}&quot;">​</a></h3><p>AI 会自动分析图片内容，为图片生成一段简洁的描述文字，该描述会保存在图片的简介字段中。</p><h2 id="create-ai-driver" tabindex="-1">创建 AI 驱动 <a class="header-anchor" href="#create-ai-driver" aria-label="Permalink to &quot;创建 AI 驱动 {#create-ai-driver}&quot;">​</a></h2><p>AI 功能的所有配置均在管理后台完成，无需手动修改配置文件。</p><p>进入管理后台，在左侧菜单找到「驱动」分组下的「AI 驱动」，点击「新建」来创建一个 AI 驱动。</p><p>创建驱动时需要填写以下信息：</p><ul><li><strong>名称</strong>：驱动名称，用于在前台展示给用户。</li><li><strong>供应商</strong>：选择一个 AI 供应商，不同供应商支持的能力不同。</li><li><strong>简介</strong>：可选，驱动的简要说明。</li><li><strong>API Key</strong>：供应商的 API 密钥。</li><li><strong>API 地址</strong>：可选，自定义 API 地址。留空将使用供应商的默认地址，输入框会以 placeholder 形式提示当前供应商的默认地址。适用于使用中转服务、代理或私有部署的场景。</li><li><strong>能力</strong>：勾选该驱动需要开启的能力（图片润色、打标签、生成描述），不支持的能力将被禁止选择。</li></ul><p>根据所选的供应商和能力，还需要配置对应的模型：</p><ul><li><strong>图片润色</strong>：需要填写图片模型 ID 和选择生成质量。系统会提供常用模型作为建议，你也可以直接输入任意模型 ID。</li><li><strong>打标签 / 生成描述</strong>：需要填写文本模型 ID。同样支持从建议列表选择或手动输入。</li></ul><h3 id="custom-prompts" tabindex="-1">自定义提示词 <a class="header-anchor" href="#custom-prompts" aria-label="Permalink to &quot;自定义提示词 {#custom-prompts}&quot;">​</a></h3><p>勾选「打标签」或「生成描述」能力后，表单底部会显示对应的提示词配置区域（默认折叠）。每个能力包含两项可配置的提示词：</p><ul><li><strong>系统指令</strong>：用于指导 AI 如何分析图片和输出结果的系统级指令。</li><li><strong>用户提示词</strong>：发送给 AI 的具体请求内容。</li></ul><p>所有提示词字段均为可选，留空时系统将使用内置的默认提示词（输入框的 placeholder 中展示了当前的默认内容）。当你需要针对特定场景调整 AI 的行为时，可以自定义提示词，例如：</p><ul><li>要求 AI 始终返回中文标签</li><li>调整生成标签的数量范围</li><li>修改描述的长度或风格要求</li><li>添加特定领域的分析指引</li></ul><div class="tip custom-block"><p class="custom-block-title">自定义模型</p><p>模型字段支持自由输入，不限于预设列表。当供应商更新了新模型，或你使用的中转服务提供了自定义模型名称时，可以直接输入对应的模型 ID。</p></div><div class="tip custom-block"><p class="custom-block-title">多驱动配置</p><p>同一个供应商可以创建多个驱动，使用不同的 API Key、API 地址或模型配置，以满足不同场景的需求。例如，你可以为同一个供应商创建两个驱动，一个使用官方 API 地址，另一个使用中转服务地址。</p></div><h3 id="provider-default-urls" tabindex="-1">各供应商默认 API 地址 <a class="header-anchor" href="#provider-default-urls" aria-label="Permalink to &quot;各供应商默认 API 地址 {#provider-default-urls}&quot;">​</a></h3><p>以下是各供应商的默认 API 地址，仅在 AI 驱动未配置自定义 API 地址时使用：</p><table tabindex="0"><thead><tr><th>供应商</th><th>默认 API 地址</th></tr></thead><tbody><tr><td>OpenAI</td><td><code>https://api.openai.com/v1</code></td></tr><tr><td>Google Gemini</td><td><code>https://generativelanguage.googleapis.com/v1beta</code></td></tr><tr><td>火山引擎（豆包）</td><td><code>https://ark.cn-beijing.volces.com/api/v3</code></td></tr><tr><td>智谱 AI（GLM）</td><td><code>https://open.bigmodel.cn/api/paas/v4</code></td></tr><tr><td>阿里百炼（通义千问）</td><td><code>https://dashscope.aliyuncs.com/compatible-mode/v1</code></td></tr><tr><td>月之暗面（Kimi）</td><td><code>https://api.moonshot.cn/v1</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>火山引擎、智谱 AI、阿里百炼、月之暗面均使用 OpenAI 兼容协议，大多数 OpenAI 兼容的中转服务都可以配合这些供应商使用。</p></div><h2 id="group-settings" tabindex="-1">角色组配置 <a class="header-anchor" href="#group-settings" aria-label="Permalink to &quot;角色组配置 {#group-settings}&quot;">​</a></h2><p>AI 功能通过角色组进行权限控制，管理员可以在编辑角色组时配置以下选项：</p><h3 id="enable-ai" tabindex="-1">启用 AI <a class="header-anchor" href="#enable-ai" aria-label="Permalink to &quot;启用 AI {#enable-ai}&quot;">​</a></h3><p>在角色组设置中开启「AI」开关后，该角色组下的所有用户即可使用 AI 功能。</p><h3 id="associate-drivers" tabindex="-1">关联 AI 驱动 <a class="header-anchor" href="#associate-drivers" aria-label="Permalink to &quot;关联 AI 驱动 {#associate-drivers}&quot;">​</a></h3><p>与储存类似，每个角色组可以关联多个 AI 驱动。只有关联了 AI 驱动的角色组，其用户才能使用对应的 AI 能力。</p><h3 id="rate-limits" tabindex="-1">使用频率限制 <a class="header-anchor" href="#rate-limits" aria-label="Permalink to &quot;使用频率限制 {#rate-limits}&quot;">​</a></h3><p>为了控制 AI 资源消耗，可以为角色组设置多个维度的使用频率限制：</p><table tabindex="0"><thead><tr><th>限制维度</th><th>说明</th></tr></thead><tbody><tr><td>每分钟限制</td><td>每分钟内允许使用的次数</td></tr><tr><td>每小时限制</td><td>每小时内允许使用的次数</td></tr><tr><td>每天限制</td><td>每天允许使用的次数</td></tr><tr><td>每周限制</td><td>每周允许使用的次数</td></tr><tr><td>每月限制</td><td>每月允许使用的次数</td></tr></tbody></table><p>将任意限制值设为 <code>0</code> 表示该维度不限制。所有限制维度同时生效，任意一个维度达到上限即无法继续使用。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>AI 功能按次计费，每处理一张图片计为一次使用。批量提交时（如同时选择 10 张图片打标签），会一次性消耗对应的次数。</p></div><h2 id="task-processing" tabindex="-1">任务处理机制 <a class="header-anchor" href="#task-processing" aria-label="Permalink to &quot;任务处理机制 {#task-processing}&quot;">​</a></h2><p>AI 任务通过<a href="./install#第四步-配置消息队列">消息队列</a>异步处理，提交任务后系统会立即返回任务状态，前端会自动轮询获取任务进度。</p><p>任务状态包括：</p><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td>等待中</td><td>任务已提交，等待队列处理</td></tr><tr><td>处理中</td><td>任务正在被 AI 处理</td></tr><tr><td>已完成</td><td>任务处理成功</td></tr><tr><td>失败</td><td>任务处理失败，可查看错误信息</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">确保消息队列正常运行</p><p>AI 功能依赖消息队列来异步处理任务。如果发现任务一直处于「等待中」状态，请检查消息队列是否已正确配置并正常运行。详见 <a href="./install#第四步-配置消息队列">安装 - 配置消息队列</a> 章节。</p></div>',47)]))}const u=e(i,[["render",l]]);export{g as __pageData,u as default};
